const levels = ['debug', 'info', 'warn', 'error'];

function log(level, message) {
  if (!levels.includes(level)) {
    throw new Error('unknown level: ' + level);
  }
  process.stderr.write(`[${level}] ${message}\n`);
}

module.exports = { log };

